framework_css:
/* Design system */
:root {
  /* Primary brand */
  --color-primary-900: #24358A; /* deep header blue */
  --color-primary-700: #0057FF; /* bright blue for accents/links */

  /* Secondary & accent */
  --color-secondary-500: #00B788; /* green from gradient */
  --color-secondary-400: #00A4FF; /* teal/blue from gradient */
  --color-accent-500: #B52C32;   /* red accent from logo */

  /* Neutrals */
  --color-neutral-0: #FFFFFF;
  --color-neutral-50: #F5F5F5;
  --color-neutral-200: #DDDDDD;

  /* Text */
  --color-text-main: #222222;
  --color-text-muted: #666666;

  /* Shadows */
  --shadow-subtle: 0 1px 0 rgba(0, 0, 0, 0.06);

  /* Typography */
  --font-heading: "Space Grotesk", Helvetica, Arial, sans-serif;
  --font-body: "Source Sans 3", -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
  --font-code: "Source Code Pro", monospace;

  --font-size-h1: 36px;
  --font-size-h2: 28px;
  --font-size-h3: 22px;
  --font-size-body: 16px;
  --font-size-small: 14px;

  --font-weight-light: 300;
  --font-weight-regular: 400;
  --font-weight-medium: 500;
  --font-weight-semibold: 600;
  --font-weight-bold: 700;

  /* Line heights */
  --line-height-tight: 1.2;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.7;

  /* Spacing scale */
  --space-1: 4px;
  --space-2: 8px;
  --space-3: 16px;
  --space-4: 24px;
  --space-5: 32px;
  --space-6: 48px;
  --space-7: 64px;

  /* Radii */
  --radius-soft: 4px;
  --radius-card: 2px;
}

/* Global resets */
*, *::before, *::after {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
}

body {
  font-family: var(--font-body);
  font-size: var(--font-size-body);
  line-height: var(--line-height-normal);
  color: var(--color-text-main);
  background-color: var(--color-neutral-0);
  text-rendering: optimizeLegibility;
  -webkit-font-smoothing: antialiased;
}

a {
  color: inherit;
  text-decoration: none;
}

a:hover,
a:focus {
  text-decoration: none;
}

img {
  max-width: 100%;
  height: auto;
  display: block;
}

.site-wrapper {
  min-height: 100vh;
  display: flex;
  flex-direction: column;
}

.container {
  max-width: 1160px;
  margin: 0 auto;
  padding-left: var(--space-4);
  padding-right: var(--space-4);
}

/* Header */
.site-header {
  position: relative;
  z-index: 100;
  box-shadow: var(--shadow-subtle);
}

/* Utility bar */
.utility-bar {
  background-color: var(--color-primary-900);
  color: var(--color-neutral-0);
  font-family: var(--font-heading);
  font-size: 14px;
}

.utility-bar-inner {
  display: flex;
  align-items: center;
  justify-content: flex-end;
  height: 40px;
}

.utility-phone {
  letter-spacing: 0.03em;
}

/* Main header */
.main-header {
  background-color: var(--color-neutral-0);
}

.header-inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding-top: var(--space-4);
  padding-bottom: var(--space-4);
}

/* Brand / logo */
.brand {
  display: flex;
  align-items: center;
  column-gap: var(--space-3);
  color: var(--color-primary-900);
}

.brand-mark {
  width: 52px;
  height: 42px;
  border-radius: 22px 4px 22px 4px; /* approximates logo silhouette */
  background: linear-gradient(135deg, var(--color-accent-500) 0%, #8E1F24 40%, var(--color-primary-900) 100%);
  position: relative;
}

.brand-mark::after {
  content: "";
  position: absolute;
  inset: 9px 12px;
  border-radius: 50%;
  background-color: var(--color-neutral-0);
}

.brand-text {
  display: flex;
  flex-direction: column;
  line-height: var(--line-height-tight);
}

.brand-name {
  font-family: var(--font-heading);
  font-weight: var(--font-weight-semibold);
  letter-spacing: 0.05em;
  text-transform: uppercase;
  font-size: 20px;
}

.brand-name-accent {
  font-weight: var(--font-weight-regular);
  margin-left: 2px;
}

.brand-tagline {
  margin-top: 2px;
  font-size: 12px;
  color: var(--color-text-muted);
}

/* Primary navigation */
.primary-nav {
  flex: 1;
}

.primary-nav-list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  justify-content: center;
  gap: var(--space-4);
}

.primary-nav-item a {
  font-family: var(--font-heading);
  font-size: 15px;
  font-weight: var(--font-weight-semibold);
  color: var(--color-primary-900);
  padding: 8px 4px;
  border-bottom: 2px solid transparent;
  transition: color 0.2s ease, border-color 0.2s ease;
}

.primary-nav-item a:hover,
.primary-nav-item a:focus {
  color: var(--color-primary-700);
  border-bottom-color: var(--color-primary-700);
}

.primary-nav-item a.is-active,
.primary-nav-item.is-active > a {
  color: var(--color-primary-700);
  border-bottom-color: var(--color-primary-700);
}

/* Main content area */
.site-main {
  flex: 1;
  padding-top: var(--space-6);
  padding-bottom: var(--space-6);
  background-color: var(--color-neutral-0);
}

/* Optional hero card styling (for use on content pages) */
.hero-card {
  max-width: 720px;
  margin: 0 auto;
  border-radius: 0;
  padding: var(--space-5);
  color: var(--color-neutral-0);
  background: linear-gradient(135deg, var(--color-secondary-500) 0%, var(--color-secondary-400) 30%, var(--color-primary-700) 65%, var(--color-primary-900) 100%);
}

/* Footer */
.site-footer {
  margin-top: auto;
  background-color: var(--color-neutral-0);
  border-top: 1px solid var(--color-neutral-200);
}

.footer-main {
  background-color: var(--color-primary-900);
  color: var(--color-neutral-0);
  padding-top: var(--space-6);
  padding-bottom: var(--space-5);
}

.footer-inner {
  display: flex;
  flex-wrap: wrap;
  align-items: flex-start;
  column-gap: var(--space-6);
  row-gap: var(--space-4);
}

.footer-brand {
  flex: 1 1 260px;
}

.brand--footer .brand-tagline {
  color: var(--color-neutral-0);
  font-size: 13px;
}

.footer-description {
  margin-top: var(--space-3);
  max-width: 360px;
  font-size: 14px;
  line-height: var(--line-height-relaxed);
  color: rgba(255, 255, 255, 0.8);
}

.footer-links {
  flex: 0 0 auto;
  min-width: 200px;
}

.footer-nav-list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.footer-nav-item a {
  font-size: 14px;
  font-weight: var(--font-weight-medium);
  color: rgba(255, 255, 255, 0.9);
}

.footer-nav-item a:hover,
.footer-nav-item a:focus {
  color: var(--color-secondary-400);
}

.footer-bottom {
  background-color: var(--color-primary-900);
  border-top: 1px solid rgba(255, 255, 255, 0.1);
}

.footer-bottom-inner {
  padding-top: var(--space-3);
  padding-bottom: var(--space-3);
  text-align: center;
}

.footer-copy {
  margin: 0;
  font-size: 13px;
  color: rgba(255, 255, 255, 0.75);
}

/* Responsive tweaks */
@media (max-width: 960px) {
  .header-inner {
    flex-direction: column;
    align-items: flex-start;
    gap: var(--space-3);
  }

  .primary-nav {
    width: 100%;
  }

  .primary-nav-list {
    justify-content: flex-start;
    flex-wrap: wrap;
    row-gap: var(--space-2);
  }
}

@media (max-width: 640px) {
  .utility-bar-inner {
    justify-content: center;
  }

  .site-main {
    padding-top: var(--space-5);
    padding-bottom: var(--space-5);
  }

  .footer-inner {
    flex-direction: column;
  }
}
